var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"야, 로봇. 거기 가만히 있지 말고 커피나 가져와.","JPN":"ちょっと、ロボット。そこでじっとしてないで、コーヒーでも持ってきなさいよ。","ENG":"Hey there, robot. Don’t just stand there. Bring me some coffee.","TWN":"喂，機器人，傻楞楞站在那幹嘛，給我來杯咖啡！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_ROBOT","text":{"KOREA":"네, 예열 개시. 커피를 끓이겠습니다.","JPN":"はい、予熱開始。コーヒーを淹れます。","ENG":"Yes, start boiling water. Your coffee will be served momentarily.","TWN":"是，預熱中，開始煮咖啡。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"이번 씬에선 파벨라와 로미오가 만나 서로에 대해 호감을 표현하는 낭만적인 장면을 촬영할 거야.","JPN":"今回のシーンでは、ファヴェーラとロミオが出会ってお互いに好感を表現するロマンチックなシーンを撮影する。","ENG":"We’re going to be filming a romantic scene where Fabella and Romeo express their feelings to each other.","TWN":"這次是帕貝拉和羅密歐相遇後，互相表示好感的浪漫場景。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"그럼 준비는 됐겠지?","JPN":"それじゃ、準備はできたか？","ENG":"So, are you ready?","TWN":"沒問題吧？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"좋아요. 그래서 로미오 역은 어디 있는데요?","JPN":"はい。ところで、ロミオ役はどこにいるんですか？","ENG":"Yes. So where’s the person that’ll be Romeo?","TWN":"好，那演羅密歐的人呢？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"아, 로미오 배역의 니콜라스는 시즌 마무리를 기념해서 휴가를 떠났어.","JPN":"あっ、ロミオ役のニコラスはシーズン終了記念でバカンスに行った。","ENG":"Oh, Nicholas, who took the role of Romeo, is on vacation to celebrate the end of the season.","TWN":"喔～原本是尼可拉斯要演羅密歐的，但戲殺青後他就去度假慶祝了。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_ROBOT","text":{"KOREA":"커피가 완성되었습니다.","JPN":"コーヒーが出来上がりました。","ENG":"Your coffee’s here.","TWN":"這是小姐的咖啡。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"아, 싸구려 냄새. 좋은 원두 좀 쓸 순 없어?","JPN":"ああ、安っぽい匂い。もうちょっと上質な豆を使いなさいよね。","ENG":"Ugh, smells like cheap coffee. Don’t you have any premium coffee beans here?","TWN":"噢，便宜貨的味道，不能用好一點的豆子嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_HATE"}}}},{"id":"L17_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"로미오 역할은 캡틴 잭이 대신 맡아줄 거야.","JPN":"ロミオ役はキャプテン・ジャックが代わりにやる。","ENG":"Captain Jack will take the role of Romeo today.","TWN":"羅密歐的角色就先由傑克船長頂著吧！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"푸웁-!","JPN":"ブフーッ！","ENG":"Pffft-!","TWN":"噗！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"STAFF_NPC_DRAMA_ROBOT","text":{"KOREA":"맡겨주십시오, 디렉터.","JPN":"お任せください、ディレクター。","ENG":"Leave it to me, Mr. Director.","TWN":"交給我吧，導演！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"콜록…","JPN":"ゲホッ……","ENG":"*Cough…*","TWN":"咕嚕…"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"잠깐. 지금 나보고 저 로봇이랑 연기를 하라고요?","JPN":"ちょっと。私に、あのロボットと演技しろって言ってるんですか？","ENG":"Wait. So you’re telling me that I should act with that robot?","TWN":"等等，現在是要我跟機器人對戲嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"적어도 배우가 연기에 몰입할 수 있는 환경은 만들어줘야 하는 거 아니에요?","JPN":"少なくとも女優が演技に集中できる環境を作るべきですよね？","ENG":"Shouldn’t you at least provide an environment where I can concentrate on my acting?","TWN":"起碼要打造一個可以讓演員發揮演技的環境吧？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"까다롭긴. 명배우는 상대를 가리지 않는 법이라고.","JPN":"うるさいな。名女優は相手を選ばないぞ。","ENG":"Don’t be so picky. A true actor is not particular about their co-actor.","TWN":"真是難搞，真正厲害的演員才不會挑人咧！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"STAFF_NPC_DRAMA_ROBOT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"그래도 이건 아니죠! 최소한 남자 대역을 데려오란 말이예요!","JPN":"でも、これはないですよ！　少なくとも男の代役を連れて来てください！","ENG":"This is still too much! At least you can bring a male stand-in!","TWN":"再不挑也不至於跟機器人對戲吧！至少給我個男的吧！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"쯧, 어쩔 수 없군.","JPN":"チッ、仕方ない。","ENG":"I guess I have no choice.","TWN":"嘖！真麻煩！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DIRECTOR_NPC_DRAMA_NULL","text":{"KOREA":"이봐, 거기! 잠깐 시간 좀 내줄 수 있나?","JPN":"おい、そこ！　ちょっと時間いいか？","ENG":"Hey, there! Do you have a moment?","TWN":"喂，那邊那個誰！你有空嗎？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"아아, 로미오.","JPN":"ああ、ロミオ。","ENG":"Ah, Romeo.","TWN":"噢～羅密歐～"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","text":{"KOREA":"내 손을 이렇게 잡아준 건, 당신이 처음이었어.","JPN":"アタシの手をこう握ってくれるのは、あんたが初めてだ。","ENG":"You’re the first person who held my hand like this.","TWN":"這是你第一次牽我的手。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"CLIENT_EXTRA_SUPPLEMENT_WOMAN","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};